// Number of days to look back
const DAYS_LIMIT = 3;
const now = new Date();
const cutoffDate = new Date(now);
cutoffDate.setDate(now.getDate() - DAYS_LIMIT);

// Ensure input exists
if (!items || items.length === 0) {
	return [];
}

// Filter recent stories
const recentItems = items.filter(item => {
	const dateValue =
		item.json.pubDate ||
		item.json.isoDate ||
		item.json.published ||
		item.json.date;

	if (!dateValue) return false;

	const itemDate = new Date(dateValue);
	return itemDate >= cutoffDate;
});

// If recent stories exist, return only them
if (recentItems.length > 0) {
	return recentItems;
}

// If no recent stories, return ONE fallback item
return [items[0]];

