// Limit to 5 articles
const articles = items.slice(0, 5);

// Build formatted output
const formattedOutput = {};

articles.forEach((item, index) => {
	const articleNumber = index + 1;

	formattedOutput[`article_${articleNumber}`] = {
		title: item.json.title || "",
		content: item.json.content || item.json.summary || "",
		imgUrl:item.json.enclosure?.url || item.json.imgUrl || ""
	};
});

// Return as single item
return [
	{
		json: formattedOutput
	}
];

